    rev_df['review_count'] = pd.to_numeric(rev_df['review_count'], errors='coerce')

biz_df = pd.DataFrame(biz_rows)

weekday_set = {'Monday','Tuesday','Wednesday','Thursday','Friday'}

# parse hours field which is stored as string like '[["Thursday","9AM–5PM"], ...]' or None

def parse_hours(x):
    if x is None:
        return None
    if isinstance(x, (list, dict)):
        return x
    s = str(x)
    if s in ('None','null','NULL',''):
        return None
    try:
        # hours are JSON-ish with double quotes
        return json.loads(s)
    except Exception:
        try:
            return ast.literal_eval(s)
        except Exception:
            return None


def to_minutes(t):
    t = t.strip()
    m = re.fullmatch(r'(\d{1,2})(?::(\d{2}))?\s*(AM|PM)', t, flags=re.I)
    if not m:
        return None
    h = int(m.group(1))
    mi = int(m.group(2) or 0)
    ap = m.group(3).upper()
    if h == 12:
        h = 0
    if ap == 'PM':
        h += 12
    return h*60 + mi


def closes_after_6pm(day_hours):
    if not day_hours or not isinstance(day_hours, str):
        return False
    s = day_hours.strip()
    if s.lower() == 'closed':
        return False
    if 'Open 24 hours' in s:
        return True
    # handle multiple intervals separated by comma
    parts = [p.strip() for p in s.split(',')]
    for p in parts:
        # format like '9AM–10PM' with en dash
        if '–' in p:
            start, end = [z.strip() for z in p.split('–', 1)]
        elif '-' in p:
            start, end = [z.strip() for z in p.split('-', 1)]
        else:
            continue
        end_m = to_minutes(end)
        if end_m is None:
            continue
        if end_m > 18*60:
            return True
    return False

biz_df['hours_parsed'] = biz_df['hours'].apply(parse_hours)

def has_weekday_after6(hours_parsed):
    if not hours_parsed or not isinstance(hours_parsed, list):
        return False
    for item in hours_parsed:
        if not (isinstance(item, (list, tuple)) and len(item) >= 2):
            continue
        day = item[0]
        hrs = item[1]
        if day in weekday_set and closes_after_6pm(hrs):
            return True
    return False

biz_df = biz_df[biz_df['hours_parsed'].apply(has_weekday_after6)].copy()

# Join with ratings
merged = biz_df.merge(rev_df[['gmap_id','avg_rating']], on='gmap_id', how='inner')
merged = merged.dropna(subset=['avg_rating'])
merged = merged.sort_values(['avg_rating','name'], ascending=[False, True]).head(5)

# format hours back to readable multi-line string
order = ['Monday','Tuesday','Wednesday','Thursday','Friday','Saturday','Sunday']

def format_hours(hours_parsed):
    if not hours_parsed:
        return None
    d = {k:v for k,v in hours_parsed if isinstance(k,str)}
    lines = []
    for day in order:
        if day in d:
            lines.append(f"{day}: {d[day]}")
    # include any unexpected keys
    for k,v in d.items():
        if k not in order:
            lines.append(f"{k}: {v}")
    return "; ".join(lines)

out = []
for _, r in merged.iterrows():
    out.append({
        'name': r['name'],
        'operating_hours': format_hours(r['hours_parsed']),
        'average_rating': float(r['avg_rating'])
    })

print('__RESULT__:')
print(json.dumps(out))

